class Solution {
    public int nextBeautifulNumber(int n) {
        for (int i = n + 1; ; i++) {
            String str = String.valueOf(i);
            boolean isBalanced = true;
            for (char c : str.toCharArray()) {
                if (str.indexOf(c) != str.lastIndexOf(c) || c - '0' != str.count(c)) {
                    isBalanced = false;
                    break;
                }
            }
            if (isBalanced) {
                return i;
            }
        }
    }
}
